const users = [{ id: 1, name: 'Alice' }];
const orders = [{ id: 101, userId: 1, total: 50 }];

const userOrders = orders
  .filter(o => o.total > 20)
  .map(o => {
    const user = users.find(u => u.id === o.userId);
    return { name: user.name, total: o.total };
  });

const items = [
  { category: 'tech', price: 100 },
  { category: 'tech', price: 200 }
];
const totals = items.reduce((acc, curr) => {
  acc[curr.category] = (acc[curr.category] || 0) + curr.price;
  return acc;
}, {});

